#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const long long NUM = 103993LL;
    const long long DEN = 33102LL;
    while (T--) {
        int K;
        scanf("%d", &K);
        if (K == 0) {
            printf("3\n");
            continue;
        }
        printf("3.");
        long long rem = NUM % DEN; // initial remainder after integer part
        for (int i = 0; i < K; ++i) {
            rem *= 10;
            int digit = (int)(rem / DEN);
            putchar('0' + digit);
            rem %= DEN;
        }
        putchar('\n');
    }
    return 0;
}

